    outseq <- as.numeric(outseq)
  }
  outpref <- as.logical(outpref)
  zero_appeal <- as.numeric(zero_appeal)
  directed <- as.logical(directed)

  on.exit(.Call(R_igraph_finalizer))
  # Function call
  res <- .Call(
    R_igraph_recent_degree_game,
    n,
    power,
    window,
    m,
    outseq,
    outpref,
    zero_appeal,
    directed
  )

  res
}

